#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        x1 = int(next(it)); x2 = int(next(it))
        y1 = int(next(it)); y2 = int(next(it))
        z1 = int(next(it)); z2 = int(next(it))
        if x2 >= x1 and y2 >= y1 and z2 <= z1:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

